-- Create Enum for User Roles
CREATE TYPE "user_role" AS ENUM ('ADMIN', 'BRAND', 'AGENCY', 'CREATOR');

-- ============================================
-- Table: users
-- Purpose: User authentication and access control
-- ============================================
CREATE TABLE "users" (
    "id" UUID NOT NULL,
    "email" VARCHAR(255) NOT NULL,
    "password_hash" VARCHAR(255) NOT NULL,
    "role" "user_role" NOT NULL DEFAULT 'BRAND',
    "created_at" TIMESTAMP(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(6) NOT NULL,

    CONSTRAINT "users_pkey" PRIMARY KEY ("id")
);

-- ============================================
-- Table: agencies
-- Purpose: Talent agencies managing creators
-- ============================================
CREATE TABLE "agencies" (
    "id" UUID NOT NULL,
    "name" VARCHAR(255) NOT NULL,
    "contact_email" VARCHAR(255),
    "created_at" TIMESTAMP(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(6) NOT NULL,

    CONSTRAINT "agencies_pkey" PRIMARY KEY ("id")
);

-- ============================================
-- Table: creators
-- Purpose: TikTok creators/KOL profiles
-- ============================================
CREATE TABLE "creators" (
    "id" UUID NOT NULL,
    "name" VARCHAR(255) NOT NULL,
    "tiktok_username" VARCHAR(255) NOT NULL,
    "tiktok_profile_url" VARCHAR(500) NOT NULL,
    "content_language" VARCHAR(100),
    "city" VARCHAR(100),
    "country" VARCHAR(100),
    "agency_id" UUID,
    "created_at" TIMESTAMP(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(6) NOT NULL,

    CONSTRAINT "creators_pkey" PRIMARY KEY ("id")
);

-- ============================================
-- Table: creator_contacts
-- Purpose: Encrypted contact information for creators
-- ============================================
CREATE TABLE "creator_contacts" (
    "id" UUID NOT NULL,
    "creator_id" UUID NOT NULL,
    "email_encrypted" TEXT,
    "whatsapp_encrypted" TEXT,
    "is_verified" BOOLEAN NOT NULL DEFAULT false,
    "created_at" TIMESTAMP(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMP(6) NOT NULL,

    CONSTRAINT "creator_contacts_pkey" PRIMARY KEY ("id")
);

-- ============================================
-- Table: contact_unlocks
-- Purpose: Audit log for contact information unlocks
-- ============================================
CREATE TABLE "contact_unlocks" (
    "id" UUID NOT NULL,
    "creator_id" UUID NOT NULL,
    "user_id" UUID NOT NULL,
    "unlocked_at" TIMESTAMP(6) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "contact_unlocks_pkey" PRIMARY KEY ("id")
);

