-- Creators -> Agencies (SET NULL on delete)
ALTER TABLE "creators" 
    ADD CONSTRAINT "creators_agency_id_fkey" 
    FOREIGN KEY ("agency_id") 
    REFERENCES "agencies"("id") 
    ON DELETE SET NULL 
    ON UPDATE CASCADE;

-- Creator Contacts -> Creators (CASCADE on delete)
ALTER TABLE "creator_contacts" 
