    FOREIGN KEY ("creator_id") 
    REFERENCES "creators"("id") 
    ON DELETE RESTRICT 
    ON UPDATE CASCADE;

-- Contact Unlocks -> Users (RESTRICT on delete - preserve audit)
ALTER TABLE "contact_unlocks" 
    ADD CONSTRAINT "contact_unlocks_user_id_fkey" 
    FOREIGN KEY ("user_id") 
    REFERENCES "users"("id") 
    ON DELETE RESTRICT 
    ON UPDATE CASCADE;

